previewCss:
.darma-loader-darma-custom-652 {--loader-secondary-color: var(--loader-secondary-color, #f97316);
  --loader-bg: var(--loader-bg, #111827);

  width: 104px;
  height: 104px;
  border-radius: 50%;
  margin: 0 auto;
  background-color: var(--loader-color, #facc15);
  background-image: radial-gradient(currentColor 4px, #0000  0),
                    radial-gradient(currentColor 4px, #0000  0),
                    radial-gradient(currentColor 4px, #0000  0),
                    radial-gradient(currentColor 4px, #0000  0);
  background-position: 24px center, 8px center, -8px center, -24px center;
  position: relative;
  box-shadow: 0 0 5px color-mix(in srgb, var(--loader-color, #facc15) 45%, transparent) inset;
  animation: darma-loader-darma-custom-652-flash 1s linear infinite;
}

.darma-loader-darma-custom-652::before , .darma-loader-darma-custom-652::after {
  content: '';
  position: absolute;
  border: 1px solid #ccc;
  border-top-color: #0000;
  left: 50%;
  top: calc(100% - 6px);
  transform: translateX(-50%);
  width: 16px;
  height: 18px;
  background: currentColor;
}

.darma-loader-darma-custom-652::before {
  width: 0px;
  height: 64px;
  transform: translate(-50% , 18px);
}

@keyframes darma-loader-darma-custom-652-flash {
  0% {
    background-image: radial-gradient(#DDD 4px, #0000  0),
        radial-gradient(#DDD 4px, #0000  0),
        radial-gradient(#DDD 4px, #0000  0),
        radial-gradient(#DDD 4px, #0000  0);
  }

  25% {
    background-image: radial-gradient(#DDD 4px, #0000  0),
      radial-gradient(#DDD 4px, #0000  0),
      radial-gradient(#DDD 4px, #0000  0),
      radial-gradient(currentColor 4px, #0000  0);
  }

  50% {
    background-image: radial-gradient(#DDD 4px, #0000  0),
      radial-gradient(#DDD 4px, #0000  0),
      radial-gradient(currentColor 4px, #0000  0),
      radial-gradient(currentColor 4px, #0000  0);
  }

  75% {
    background-image: radial-gradient(#DDD 4px, #0000  0),
        radial-gradient(currentColor 4px, #0000  0),
        radial-gradient(currentColor 4px, #0000  0),
        radial-gradient(currentColor 4px, #0000  0);
  }

  100% {
    background-image: radial-gradient(currentColor 4px, #0000  0),
        radial-gradient(currentColor 4px, #0000  0),
        radial-gradient(currentColor 4px, #0000  0),
        radial-gradient(currentColor 4px, #0000  0);
  }
}

